import java.io.*;import java.util.stream.*;import java.util.*;interface Main{static void main(String[]l)throws Exception{BufferedReader r=new BufferedReader(new InputStreamReader(System.in));int c=Integer.valueOf(r.readLine());r.lines().limit(c).collect(Collectors.groupingBy(s -> s.split("\\.")[1],TreeMap::new,Collectors.counting())).entrySet().forEach(e->System.out.println(e.getKey()+" "+e.getValue()));}}